Here's a modern MSTest 3.x approach for testing `DataFetcher`, focusing on cancellation and timeouts:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode statusCode = HttpStatusCode.OK,
        string content = "response-body",
        TimeSpan? delay = null)
    {
        var handler = new FakeHandler(statusCode, content, delay);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, _) = CreateFetcher(content: "hello world");

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NonSuccessStatusCode_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — slow server + pre-canceled token
        var (fetcher, _) = CreateFetcher(delay: TimeSpan.FromSeconds(30));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // guard: test fails if it takes longer than 3 s
    public async Task FetchAsync_TimeoutViaCancellation_ThrowsBeforeServerResponds()
    {
        // Arrange — server takes 30 s, but we cancel after 50 ms
        var (fetcher, _) = CreateFetcher(delay: TimeSpan.FromSeconds(30));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CooperativeTimeout_UseTestContextToken()
    {
        // TestContext.CancellationToken fires when [Timeout] expires,
        // so passing it into the SUT gives cooperative cancellation for free.
        var (fetcher, _) = CreateFetcher(content: "fast");

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // --- Fake handler (no mocking library required) ---
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _statusCode;
        private readonly string _content;
        private readonly TimeSpan? _delay;

        public FakeHandler(
            HttpStatusCode statusCode = HttpStatusCode.OK,
            string content = "",
            TimeSpan? delay = null)
        {
            _statusCode = statusCode;
            _content = content;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay is { } d)
            {
                await Task.Delay(d, cancellationToken); // throws if canceled
            }

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `FakeHandler` extends `HttpMessageHandler` | Lets you control `HttpClient` without a mocking library |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]` — lets you inspect the exception |
| `[Timeout(N)]` + `TestContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| Separate `CancellationTokenSource` with deadline | Tests your code's cancellation path independently of MSTest's timeout |
| Pre-canceled `cts.Cancel()` | Verifies cancellation is checked eagerly, not just after a delay |
| Sealed class + constructor-injected `TestContext` | Modern MSTest 3.x best practice |

**The critical takeaway:** always pass `TestContext.CancellationToken` (or your own token) into the async call under test. Without it, a hung `FetchAsync` would block the test runner indefinitely — `[Timeout]` alone can't force-kill the work.
